def get_applications_filtered(status_filter=None):
    applications = load_applications()
    if status_filter and status_filter.strip():
        filtered = [a for a in applications if a['status'].lower() == status_filter.lower()]
    else:
        filtered = applications
    return filtered


def filter_jobs(jobs, category_name=None, location=None, search_query=None):
    results = jobs
    if category_name:
        results = [j for j in results if j['category'] == category_name]
    if location:
        results = [j for j in results if j['location'].lower() == location.lower()]
    if search_query:
        lowerq = search_query.lower()
        results = [j for j in results if lowerq in j['title'].lower() or lowerq in get_company_by_id(j['company_id'])['company_name'].lower() or lowerq in j['location'].lower()]
    return results


def filter_companies(companies, search_query=None):
    if not search_query:
        return companies
    lowerq = search_query.lower()
    filtered = [c for c in companies if lowerq in c['company_name'].lower() or lowerq in c['industry'].lower()]
    return filtered


def next_id(items, key_name):
    if not items:
        return 1
    return max(i[key_name] for i in items) + 1


def format_salary_range(smin, smax):
