        if resume_file is None or resume_file.filename == '':
            errors['resume_file'] = 'Resume file is required.'
        if not cover_letter:
            errors['cover_letter'] = 'Cover letter is required.'

        if errors:
            form_errors = errors
        else:
            # Save resume file
            filename = resume_file.filename
            resume_save_path = os.path.join(UPLOAD_FOLDER, filename)
