                timestamp = datetime.datetime.now().strftime('%Y%m%d%H%M%S')
                filename = f"{base}_{timestamp}{ext}"
                resume_save_path = os.path.join(UPLOAD_FOLDER, filename)
            resume_file.save(resume_save_path)

            # Create new resume entry
            resumes = load_resumes()
            new_resume_id = next_id(resumes, 'resume_id')
            upload_date = datetime.datetime.now().strftime('%Y-%m-%d')
            # Summary: use first 100 characters of cover_letter without newlines
            summary = cover_letter.replace('\n', ' ')[:100]
            resumes.append({
                'resume_id': new_resume_id,
                'applicant_name': applicant_name,
                'applicant_email': applicant_email,
                'filename': filename,
                'upload_date': upload_date,
                'summary': summary
            })
            save_resumes(resumes)

            # Create new application entry
            applications = load_applications()
            new_application_id = next_id(applications, 'application_id')
            applied_date = datetime.datetime.now().strftime('%Y-%m-%d')
            applications.append({
