from flask import Flask, render_template, redirect, url_for, request, abort
import os
import datetime

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev-secret-key'

DATA_DIR = 'data'
UPLOAD_FOLDER = 'uploads'
os.makedirs(UPLOAD_FOLDER, exist_ok=True)

# --- Utilities to load and save data ---

def load_jobs():
    jobs = []
    try:
        with open(os.path.join(DATA_DIR, 'jobs.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 9:
                    continue
                job = {
                    'job_id': int(parts[0]),
                    'title': parts[1],
                    'company_id': int(parts[2]),
                    'location': parts[3],
                    'salary_min': int(parts[4]),
                    'salary_max': int(parts[5]),
                    'category': parts[6],
                    'description': parts[7],
                    'posted_date': parts[8]
                }
                jobs.append(job)
    except FileNotFoundError:
        pass
    return jobs


def load_companies():
    companies = []
    try:
        with open(os.path.join(DATA_DIR, 'companies.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 6:
                    continue
                company = {
                    'company_id': int(parts[0]),
                    'company_name': parts[1],
                    'industry': parts[2],
                    'location': parts[3],
                    'employee_count': int(parts[4]),
                    'description': parts[5]
                }
                companies.append(company)
    except FileNotFoundError:
        pass
    return companies


def load_categories():
    categories = []
    try:
        with open(os.path.join(DATA_DIR, 'categories.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 3:
                    continue
                category = {
                    'category_id': int(parts[0]),
                    'category_name': parts[1],
                    'description': parts[2]
                }
                categories.append(category)
    except FileNotFoundError:
        pass
    return categories


def load_applications():
    applications = []
    try:
        with open(os.path.join(DATA_DIR, 'applications.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 7:
                    continue
                application = {
                    'application_id': int(parts[0]),
                    'job_id': int(parts[1]),
                    'applicant_name': parts[2],
                    'applicant_email': parts[3],
                    'status': parts[4],
                    'applied_date': parts[5],
                    'resume_id': int(parts[6])
                }
                applications.append(application)
    except FileNotFoundError:
        pass
    return applications


def load_resumes():
    resumes = []
    try:
        with open(os.path.join(DATA_DIR, 'resumes.txt'), 'r', encoding='utf-8') as f:
            for line in f:
                line = line.strip()
                if not line:
                    continue
                parts = line.split('|')
                if len(parts) != 6:
                    continue
                resume = {
                    'resume_id': int(parts[0]),
                    'applicant_name': parts[1],
                    'applicant_email': parts[2],
                    'filename': parts[3],
                    'upload_date': parts[4],
                    'summary': parts[5]
                }
                resumes.append(resume)
    except FileNotFoundError:
        pass
    return resumes


def save_applications(applications):
    try:
        with open(os.path.join(DATA_DIR, 'applications.txt'), 'w', encoding='utf-8') as f:
            for a in applications:
                f.write(f"{a['application_id']}|{a['job_id']}|{a['applicant_name']}|{a['applicant_email']}|{a['status']}|{a['applied_date']}|{a['resume_id']}\n")
    except Exception:
        pass


def save_resumes(resumes):
    try:
        with open(os.path.join(DATA_DIR, 'resumes.txt'), 'w', encoding='utf-8') as f:
            for r in resumes:
                f.write(f"{r['resume_id']}|{r['applicant_name']}|{r['applicant_email']}|{r['filename']}|{r['upload_date']}|{r['summary']}\n")
    except Exception:
        pass


# Utility to get next ID

def next_id(items, key):
    if not items:
        return 1
    return max(item[key] for item in items) + 1


# Lookup helpers

def get_company_by_id(company_id):
    companies = load_companies()
    for c in companies:
        if c['company_id'] == company_id:
            return c
    return None


def get_job_by_id(job_id):
    jobs = load_jobs()
    for j in jobs:
        if j['job_id'] == job_id:
            return j
    return None


def get_resume_by_id(resume_id):
    resumes = load_resumes()
    for r in resumes:
        if r['resume_id'] == resume_id:
            return r
    return None


# Filters

def filter_jobs(jobs, category=None, location=None, search_query=None):
    filtered = jobs
    if category:
        filtered = [j for j in filtered if j['category'] == category]
    if location:
        filtered = [j for j in filtered if j['location'].lower() == location.lower()]
    if search_query:
        q = search_query.lower()
        def job_match(j):
            comp = get_company_by_id(j['company_id'])
            if not comp:
                return False
            return (q in j['title'].lower() or q in comp['company_name'].lower() or q in j['location'].lower())
        filtered = [j for j in filtered if job_match(j)]
    return filtered


def filter_companies(companies, search_query=None):
    if not search_query:
        return companies
    q = search_query.lower()
    filtered = [c for c in companies if (q in c['company_name'].lower() or q in c['industry'].lower())]
    return filtered


